import { test, expect } from '@playwright/test';
import * as path from 'path';
import { fileURLToPath } from 'url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const localUrl = `file://${path.resolve(__dirname, 'target-app/login.html')}`;

test.describe('Login Page', () => {
  test.beforeEach(async ({ page }) => {
    await page.goto(localUrl);
  });

  test('should have correct page title', async ({ page }) => {
    await expect(page).toHaveTitle('Login — AutoHeal Demo');
  });

  test('should display login form with all fields', async ({ page }) => {
    const form = page.getByRole('form');
    const usernameInput = page.getByPlaceholder('Username');
    const passwordInput = page.getByPlaceholder('Password');
    const submitButton = page.getByRole('button', { name: 'Sign In' });

    await expect(form).toBeVisible();
    await expect(usernameInput).toBeVisible();
    await expect(passwordInput).toBeVisible();
    await expect(submitButton).toBeVisible();
  });

  test('should submit form and update help text with username', async ({ page }) => {
    const usernameInput = page.getByLabel('Username');
    const submitButton = page.getByRole('button', { name: 'Sign In' });
    const username = 'testuser';
    const helpDiv = page.getByText(`Signing in as ${username}`, { exact: true });

    await usernameInput.fill(username);
    await submitButton.click();

    await expect(helpDiv).toHaveText(`Signing in as ${username}`, { timeout: 10000 });
  });

  test('should navigate to dashboard after form submission', async ({ page }) => {
    const usernameInput = page.getByPlaceholder('Username');
    const submitButton = page.getByRole('button', { name: 'Sign In' });

    await usernameInput.fill('testuser');
    
    await Promise.all([
      page.waitForURL('**/dashboard.html'),
      submitButton.click()
    ]);

    await expect(page).toHaveURL(/.*dashboard\.html/);
  });
});
